using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=getchar();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
int n;
string s;
int ans;
bool check(int x)
{
    int m=0;
    int l=-1e9;
    FOR(i,0,n-1)
    {
        if(s[i]=='1'&&i-l<x)
        {
            return 0;
        }
        if(s[i]=='1')
        {
            l=i;
        }
    }
    l=-1e9;
    FOR(i,0,n-1)
    {
        if(s[i]=='1'&&i-l<x)
        {
            m--;
        }
        if((i-l>=x)&&s[i]!='1')
        {
            l=i;
            m++;
        }
        if(s[i]=='1')
        {
            l=i;
        }
    }
    return m>=2;
}
signed main(void)
{
    n=read();
    cin>>s;
    int l=1,r=1e5+5;
    wh(l<=r)
    {
        if(check(mid))
        {
            ans=mid;
            l=mid+1;
        }
        else
        {
            r=mid-1;
        }
    }
    writeln(ans);
    return false;
}
